     7→func TestDefaultEnhancedSignatureGenerator_ComputeSignatureSimilarity(t *testing.T) {
     8→	generator := NewEnhancedSignatureGenerator(nil)
     9→
    10→	tests := []struct {
    11→		name             string
    12→		sig1             string
    13→		sig2             string
    14→		lang             string
    15→		compiler         string
    16→		expectSimilarity float64
    17→	}{
    18→		{
    19→			name:             "identical signatures",
    20→			sig1:             "abcdef1234567890",
    21→			sig2:             "abcdef1234567890",
    22→			lang:             "java",
    23→			compiler:         "javac",
    24→			expectSimilarity: 1.0,
    25→		},
    26→		{
    27→			name:             "completely different signatures",
    28→			sig1:             "0000000000000000",
    29→			sig2:             "ffffffffffffffff",
    30→			lang:             "java",
    31→			compiler:         "javac",
    32→			expectSimilarity: 0.0,
    33→		},
    34→		{
    35→			name:             "partially similar signatures",
    36→			sig1:             "abcd00000000000",
    37→			sig2:             "abcd11111111111",
    38→			lang:             "java",
    39→			compiler:         "javac",
    40→			expectSimilarity: 0.25, // 4 out of 16 characters match
    41→		},
    42→	}
    43→
    44→	for _, tt := range tests {
    45→		t.Run(tt.name, func(t *testing.T) {
    46→			similarity := generator.ComputeSignatureSimilarity(tt.sig1, tt.sig2, tt.lang, tt.compiler)
    47→			if similarity != tt.expectSimilarity {
    48→				t.Errorf("ComputeSignatureSimilarity() = %v, want %v", similarity, tt.expectSimilarity)
    49→			}
    50→		})
    51→	}
    52→}
