    54→func TestDefaultEnhancedSignatureGenerator_ComputePatchSimilarity(t *testing.T) {
    55→	generator := NewEnhancedSignatureGenerator(nil)
    56→
    57→	tests := []struct {
    58→		name      string
    59→		patch1    []byte
    60→		patch2    []byte
    61→		expectSim float64
    62→		expectGT  float64 // expect greater than this value
    63→	}{
    64→		{
    65→			name:      "identical patches",
    66→			patch1:    []byte("--- [FILE_A]\n+++ [FILE_B]\n+import java.util.List;"),
    67→			patch2:    []byte("--- [FILE_A]\n+++ [FILE_B]\n+import java.util.List;"),
    68→			expectSim: 1.0,
    69→		},
    70→		{
    71→			name:     "similar imports",
    72→			patch1:   []byte("--- [FILE_A]\n+++ [FILE_B]\n+import java.util.List;"),
    73→			patch2:   []byte("--- [FILE_A]\n+++ [FILE_B]\n+import java.util.Set;"),
    74→			expectGT: 0.5, // Should have reasonable similarity due to structure
    75→		},
    76→		{
    77→			name:     "completely different patches",
    78→			patch1:   []byte("--- [FILE_A]\n+++ [FILE_B]\n+public class A {}"),
    79→			patch2:   []byte("--- [FILE_A]\n+++ [FILE_B]\n-private int x;"),
    80→			expectGT: 0.0, // Should be low but not zero due to structure similarity
    81→		},
    82→	}
    83→
    84→	for _, tt := range tests {
    85→		t.Run(tt.name, func(t *testing.T) {
    86→			similarity := generator.ComputePatchSimilarity(tt.patch1, tt.patch2)
    87→
    88→			if tt.expectSim > 0 {
    89→				if similarity != tt.expectSim {
    90→					t.Errorf("ComputePatchSimilarity() = %v, want %v", similarity, tt.expectSim)
    91→				}
    92→			} else {
    93→				if similarity <= tt.expectGT {
    94→					t.Errorf("ComputePatchSimilarity() = %v, want > %v", similarity, tt.expectGT)
    95→				}
    96→			}
    97→		})
    98→	}
    99→}
