   101→func TestDefaultEnhancedSignatureGenerator_FindSimilarSignatures(t *testing.T) {
   102→	generator := NewEnhancedSignatureGenerator(nil)
   103→
   104→	targetSig := "abcd123456789000"
   105→	candidateSigs := []string{
   106→		"abcd123456789111", // High similarity
   107→		"abcd000000000000", // Medium similarity
   108→		"0000000000000000", // Low similarity
   109→		"abcd123456789000", // Exact match (should be excluded)
   110→		"ffffffffffffffff", // No similarity
   111→	}
   112→
   113→	results := generator.FindSimilarSignatures(targetSig, candidateSigs, "java", "javac", 0.5)
   114→
   115→	// Should find signatures above threshold (0.5) but exclude exact match
   116→	if len(results) == 0 {
   117→		t.Error("Expected to find similar signatures, got none")
   118→	}
   119→
   120→	// Results should be sorted by similarity descending
   121→	for i := 1; i < len(results); i++ {
   122→		if results[i-1].Similarity < results[i].Similarity {
   123→			t.Errorf("Results not sorted properly: %v < %v", results[i-1].Similarity, results[i].Similarity)
   124→		}
   125→	}
   126→
   127→	// Should not include exact match
   128→	for _, result := range results {
   129→		if result.Signature == targetSig {
   130→			t.Error("Results should not include exact match of target signature")
   131→		}
   132→	}
   133→}
