   142→
   143→	patches := map[string][]byte{
   144→		"target123": patch1,
   145→		"similar1":  patch2, // Similar import
   146→		"different": patch3, // Different content
   147→	}
   148→
   149→	candidateFingerprints := []string{"similar1", "different"}
   150→
   151→	results := generator.FindSimilarPatches(targetFingerprint, candidateFingerprints, patches, 0.3)
   152→
   153→	if len(results) == 0 {
   154→		t.Error("Expected to find similar patches, got none")
   155→	}
   156→
   157→	// Results should be sorted by similarity descending
   158→	for i := 1; i < len(results); i++ {
   159→		if results[i-1].Similarity < results[i].Similarity {
   160→			t.Errorf("Results not sorted properly: %v < %v", results[i-1].Similarity, results[i].Similarity)
   161→		}
   162→	}
   163→
   164→	// Should include patch size information
   165→	for _, result := range results {
   166→		if result.PatchSize <= 0 {
   167→			t.Errorf("Expected positive patch size, got %v", result.PatchSize)
   168→		}
