   190→func TestDefaultEnhancedSignatureGenerator_TokenExtraction(t *testing.T) {
   191→	generator := NewEnhancedSignatureGenerator(nil)
   192→
   193→	patch := []byte(`--- [FILE_A]
   194→+++ [FILE_B]  
   195→+import java.util.List;
   196→+public class Test {
   197→-    private int oldVar;
   198→+    private String newVar;
   199→ }`)
   200→
   201→	tokens := generator.extractChangeTokens(patch)
   202→
   203→	expectedTokens := []string{"import", "java", "util", "List", "public", "class", "Test", "private", "int", "oldVar", "private", "String", "newVar"}
   204→
   205→	// Check that expected tokens are present
   206→	tokenMap := make(map[string]bool)
   207→	for _, token := range tokens {
   208→		tokenMap[token] = true
   209→	}
   210→
   211→	for _, expected := range expectedTokens {
   212→		if !tokenMap[expected] {
   213→			t.Errorf("Expected token %q not found in extracted tokens: %v", expected, tokens)
   214→		}
   215→	}
   216→}
